import React, { useState } from "react";

export default (props) => {
  const [input1, onChangeInput1] = useState('');
  const [input2, onChangeInput2] = useState('');
  const [input3, onChangeInput3] = useState('');
  const [input4, onChangeInput4] = useState('');
  const [input5, onChangeInput5] = useState('');

  const [toast, setToast] = useState(null);

  const showToast = (message) => {
    setToast(message);
    setTimeout(() => setToast(null), 2500);
  }

  return (
    <div className="min-h-screen flex justify-center items-start bg-gray-100 py-10 overflow-auto relative">
      
      {/* Toast nổi lên */}
      {toast && (
        <div className="fixed top-10 right-10 bg-black text-white px-6 py-3 rounded-lg shadow-lg z-50 animate-slide-down">
          {toast}
        </div>
      )}

      <div className="flex flex-col items-start bg-white w-[1440px] rounded-[10px] shadow-lg p-5">

        {/* Header */}
        <div className="flex items-start self-stretch bg-[#88BCF8] py-[3px] mb-2 rounded-[10px]">
          {/* ... giữ nguyên header của cậu ... */}
        </div>

        {/* Body */}
        <div className="flex items-start mb-[50px] ml-[27px]">
          <div className="flex flex-col items-center bg-[#88BCF8] w-[88px] p-[23px] mt-[38px] mr-[65px] gap-[30px] rounded-[10px] border-2 border-solid border-[#00000000]">
            {/* Sidebar icons */}
          </div>

          <div className="flex flex-col items-start w-[1260px] gap-4">

            {/* Nút “Chào bạn” */}
            <button 
              className="flex flex-col items-center bg-[#FFDEF8CF] text-left w-[1088px] py-[11px] rounded-[10px] border-0"
              onClick={()=>showToast("Xin chào bạn!")}>
              <span className="text-black text-xl">{"Chào bạn"}</span>
            </button>

            {/* Input “Hôm nay bạn thế nào...” */}
            <div className="flex items-center bg-[#A2D3FF] py-[13px] rounded-[10px]">
              <img
                src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/d7m3bryx_expires_30_days.png"} 
                className="w-[58px] h-[58px] ml-[50px] mr-[51px] object-fill"
              />
              <input
                placeholder={"Hôm nay bạn thế nào chia sẻ với tui đi!!"}
                value={input2}
                onChange={(event)=>onChangeInput2(event.target.value)}
                className="text-black bg-[#F6FEFF] text-xl w-[916px] py-4 pl-[180px] pr-[360px] mr-3 rounded-[50px] border-0"
              />
              <button
                className="ml-4 bg-blue-400 text-white px-5 py-2 rounded-lg"
                onClick={() => {
                  if(input2.trim() !== "") {
                    showToast(`Bạn vừa gửi: "${input2}"`);
                    onChangeInput2('');
                    // Hiển thị thông báo “Bạn của bạn đăng tin” kiểu toast luôn
                    setTimeout(() => showToast("Bạn của bạn đăng tin"), 500); // delay tí để hiện sau khi gửi
                  }
                }}
              >
                Gửi
              </button>
            </div>

            {/* Các bài post khác, comment ... vẫn giữ nguyên như cậu viết */}
          </div>
        </div>
      </div>
    </div>
  )
}
